"""Circle packing: 26 equal circles via hexagonal (offset) lattice in [0,1]x[0,1]."""
import numpy as np


def construct_packing():
    n = 26
    sqrt3 = np.sqrt(3.0)
    r_vert = 1.0 / (2.0 + 5.0 * sqrt3)
    r_horz = 1.0 / 10.0
    r = min(r_vert, r_horz) * (1.0 - 1e-9)

    centers = []
    y0 = r
    dy = r * sqrt3
    for i in range(6):
        if i % 2 == 0:
            xs = [r + j * 2.0 * r for j in range(5)]
        else:
            xs = [2.0 * r + j * 2.0 * r for j in range(4)]
        y = y0 + i * dy
        for x in xs:
            centers.append([x, y])

    centers = np.array(centers[:n])
    radii = np.full(n, r)
    return centers, radii, float(np.sum(radii))
# EVOLVE-BLOCK-END


def run_packing():
    return construct_packing()


if __name__ == "__main__":
    centers, radii, sum_radii = run_packing()
    print(f"Sum of radii: {sum_radii:.6f}")

